\[
\begin{align}
\binom{6}{2}&amp;=\frac{6!}{2!\cdot(6-2)!}=\\
&amp;=\frac{6!}{2!\cdot 4!}=\\
&amp;=\frac{\color{red}{4!}\cdot 5\cdot 6}{2!\cdot \color{red}{4!}}=\\
&amp;=\frac{\require{cancel}\cancel{\color{red}{4!}}\cdot 5\cdot 6}{2!\cdot \require{cancel}\cancel{\color{red}{4!}}}=\\
&amp;=\frac{5\cdot 6}{1\cdot 2}
\end{align}
\]

\[
\begin{align}
\binom{6}{4}&amp;=\frac{6!}{4!\cdot(6-4)!}=\\
&amp;=\frac{6!}{4!\cdot 2!}=\\
&amp;=\frac{\color{red}{4!}\cdot 5\cdot 6}{\color{red}{4!}\cdot 2!}=\\
&amp;=\frac{\require{cancel}\cancel{\color{red}{4!}}\cdot 5\cdot 6}{\require{cancel}\cancel{\color{red}{4!}}\cdot 2!}=\\
&amp;=\frac{5\cdot 6}{1\cdot 2}
\end{align}
\]
